    - "scans/onboard-scan-<iso-ts>.json schema (exact field names): { scan_timestamp: ISO-8601, external_repo: 'owner/repo', tool_version: string, inputs_read: [{path: string, sha256: string, summary: string}], proposed_gaps: [{title: string, domain: string, priority: 'P0'|'P1'|'P2'|'P3', effort: 'xs'|'s'|'m'|'l', confidence: 'high'|'med'|'low', source_of_evidence: {input_path: string, section: string, excerpt: string}, acceptance_criteria_draft: [string]}] }."
    - "memory/snapshot-<iso-date>.json schema: { snapshot_timestamp: ISO-8601, external_repo: 'owner/repo', git_head_sha: string, open_issues_count: u32, open_prs_count: u32, last_commit_iso: ISO-8601, last_30d_commit_count: u32, intent_files_present: [string] }."
    - "signals/{issues,prs,commits}.jsonl schemas: streaming-append JSONL, one event per line. issues.jsonl: { ts: ISO-8601, number: u32, action: 'opened'|'closed'|'reopened'|'commented'|'labeled', title: string }. prs.jsonl: { ts: ISO-8601, number: u32, action: 'opened'|'merged'|'closed'|'reviewed', title: string, head_repo: string }. commits.jsonl: { ts: ISO-8601, sha: string, author: string, summary: string }."
